<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();require_permission($pdo,'manage_attendance');require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$emps=$pdo->query("SELECT id,full_name FROM mb_employees WHERE status='active' ORDER BY full_name")->fetchAll(PDO::FETCH_ASSOC);$projects=mb_project_options($pdo);if($_SERVER['REQUEST_METHOD']==='POST'){try{csrf_verify();if(($_POST['action']??'')==='save'){$pdo->prepare("INSERT INTO mb_attendance (employee_id,project_id,attendance_date,time_in,time_out,status,notes,created_by) VALUES (?,?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE project_id=VALUES(project_id),time_in=VALUES(time_in),time_out=VALUES(time_out),status=VALUES(status),notes=VALUES(notes)")->execute([(int)$_POST['employee_id'],$_POST['project_id']?:null,$_POST['attendance_date']?:date('Y-m-d'),$_POST['time_in']?:null,$_POST['time_out']?:null,$_POST['status']??'present',trim($_POST['notes']??''),(int)$_SESSION['user_id']]);mb_set_success('Attendance saved.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('attendance.php');}$rows=$pdo->query("SELECT a.*,e.full_name,p.name project_name FROM mb_attendance a JOIN mb_employees e ON e.id=a.employee_id LEFT JOIN mb_projects p ON p.id=a.project_id ORDER BY a.attendance_date DESC,a.id DESC LIMIT 300")->fetchAll(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Attendance','Attendance');?><?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="mb-card mb-3"><div class="mb-card-header"><strong>Daily attendance</strong><button class="btn btn-primary" data-mb-open-modal="attModal">Log Attendance</button></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>Date</th><th>Employee</th><th>Project</th><th>Time In</th><th>Time Out</th><th>Status</th><th>Notes</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars($r['attendance_date'])?></td><td><?=htmlspecialchars($r['full_name'])?></td><td><?=htmlspecialchars($r['project_name']?:'-')?></td><td><?=htmlspecialchars($r['time_in'])?></td><td><?=htmlspecialchars($r['time_out'])?></td><td><span class="mb-badge"><?=htmlspecialchars($r['status'])?></span></td><td><?=htmlspecialchars($r['notes'])?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="7" class="text-center text-muted py-4">No attendance logs.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="attModal"><div class="modal-dialog"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><div class="modal-header"><h5 class="modal-title">Log Attendance</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><label class="form-label w-100">Employee<select required class="form-select" name="employee_id"><?php foreach($emps as $e):?><option value="<?=(int)$e['id']?>"><?=htmlspecialchars($e['full_name'])?></option><?php endforeach;?></select></label><label class="form-label w-100">Project<select class="form-select" name="project_id"><option value="">No project</option><?php foreach($projects as $p):?><option value="<?=(int)$p['id']?>"><?=htmlspecialchars($p['name'])?></option><?php endforeach;?></select></label><label class="form-label w-100">Date<input class="form-control" type="date" name="attendance_date" value="<?=date('Y-m-d')?>"></label><div class="row"><div class="col"><label class="form-label w-100">Time In<input class="form-control" type="time" name="time_in"></label></div><div class="col"><label class="form-label w-100">Time Out<input class="form-control" type="time" name="time_out"></label></div></div><label class="form-label w-100">Status<input class="form-control" name="status" value="present"></label><label class="form-label w-100">Notes<textarea class="form-control" name="notes"></textarea></label></div><div class="modal-footer"><button class="btn btn-primary">Save Attendance</button></div></form></div></div><?php mb_workspace_footer();?>